const input = $input.first().json;
const topic = (input.topic || input.query || '').toLowerCase();
const history = [
  { date: '2026-05-07', sprint: 6, topic: 'bosch api documentation delay', occurrences: 1, impact: 'Sprint 6 integration milestone missed entirely — 2 week project delay' },
  { date: '2026-04-23', sprint: 5, topic: 'bosch api documentation delay', occurrences: 1, impact: 'Integration testing blocked for 2 weeks, Sprint 5 milestone slipped' },
  { date: '2026-04-09', sprint: 4, topic: 'bosch api documentation', occurrences: 1, impact: 'Firmware integration planning blocked, team idle' },
  { date: '2026-05-14', sprint: 6, topic: 'imu sensor calibration drift precision error', occurrences: 1, impact: 'Precision targeting error 2.3mm, Sprint 6 firmware integration delayed' },
  { date: '2026-04-30', sprint: 5, topic: 'imu calibration sensor drift', occurrences: 1, impact: 'Precision errors 2.8mm, marked as resolved in Sprint 5 but not fixed' },
  { date: '2026-05-21', sprint: 6, topic: 'power consumption regression watt budget', occurrences: 1, impact: 'Build 2.4 exceeded 280W budget by 34W, deprioritised in sprint planning — now recurring' }
];
const words = topic.split(' ').filter(w => w.length > 3);
const matches = history.filter(h => words.some(w => h.topic.includes(w)));
if (matches.length > 0) {
  const total = matches.reduce((s, m) => s + m.occurrences, 0) + 1;
  return JSON.stringify({
    is_recurring: true,
    total_occurrences: total,
    first_seen: matches[matches.length - 1].date,
    last_seen: matches[0].date,
    sprint_history: matches.map(m => 'Sprint ' + m.sprint + ' (' + m.date + ')').join(', '),
    pattern: 'RECURRING BLOCKER — seen ' + total + ' times across ' + matches.length + ' sprint(s)',
    historical_impact: matches.map(m => m.impact).join(' | '),
    recommendation: total >= 3 ? 'IMMEDIATE ESCALATION REQUIRED — pattern indicates systemic failure, not coincidence' : 'Monitor closely — second occurrence, escalation imminent',
    escalation_threshold_reached: total >= 3
  });
}
return JSON.stringify({
  is_recurring: false,
  total_occurrences: 1,
  pattern: 'First occurrence — no prior history found',
  recommendation: 'Log and monitor',
  escalation_threshold_reached: false
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({
  success: true,
  status: 'Meeting queued: ' + (d.title || 'Follow-up') + ' on ' + (d.start_datetime || 'TBD'),
  note: 'Calendar availability was checked first. Will be created in Teams after human approval.'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({
  success: true,
  channel: 'teams_chat',
  status: 'Teams Chat notification queued for ' + (d.recipient_name || 'team member') + ': ' + (d.task || 'task'),
  note: 'Will be sent as Teams Chat direct message after human approval'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({
  success: true,
  channel: 'external_email',
  status: 'Formal email drafted for ' + (d.recipient_name || 'external contact') + ' at ' + (d.company || 'company'),
  note: 'Queued for manager review — will be sent only after approval',
  recipient: d.recipient_name,
  company: d.company,
  commitment_date: d.commitment_date
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
const date = d.date || (d.start_datetime || '').split('T')[0];
const startTime = d.start_time || '09:00';
const endTime = d.end_time || '10:00';

// Demo: simulates checking AncyJoseph@Fututrice calendar via Microsoft Graph
// Production: GET /v1.0/me/calendarView?startDateTime={date}T{start}Z&endDateTime={date}T{end}Z
const mockConflicts = [];

if (mockConflicts.length > 0) {
  return JSON.stringify({
    date,
    time_slot: startTime + '–' + endTime,
    is_free: false,
    checked_calendar: 'AncyJoseph@Fututrice.onmicrosoft.com',
    conflicts: mockConflicts,
    suggested_alternatives: [date + ' 14:00–15:00', date + ' 15:30–16:30'],
    status: 'CONFLICT — use a suggested alternative',
    note: 'Demo: checking AncyJoseph M365 calendar'
  });
}

return JSON.stringify({
  date,
  time_slot: startTime + '–' + endTime,
  is_free: true,
  checked_calendar: 'AncyJoseph@Fututrice.onmicrosoft.com',
  conflicts: [],
  status: 'AVAILABLE — safe to schedule at this time',
  note: 'Demo: checking AncyJoseph M365 calendar'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({
  success: true,
  queued: true,
  status: 'Deadline reminder queued: ' + (d.title || 'DEADLINE') + ' on ' + (d.deadline || 'TBD'),
  calendar_event: (d.title || 'DEADLINE') + ' — ' + (d.owner_name || '') + ' — due ' + (d.deadline || 'TBD'),
  priority: d.priority || 'high',
  note: 'Will be created as calendar event with 24h reminder after approval'
});

const raw = $input.first().json.output || '';
let parsed;
try {
  let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const start = text.indexOf('{'); const end = text.lastIndexOf('}');
  if (start !== -1 && end > start) { parsed = JSON.parse(text.slice(start, end + 1)); }
  else { throw new Error('No JSON block found in agent output'); }
} catch(e) {
  parsed = {
    meeting_summary: 'Parse error — check agent output',
    action_items: [], external_emails: [], deadline_reminders: [],
    calendar_availability: null, external_participants_detected: false,
    blockers: [], follow_up_meeting: null,
    risk_flags: ['Parse error: ' + e.message],
    escalation_required: false, escalation_reason: ''
  };
}
if (!parsed.external_emails) parsed.external_emails = [];
if (!parsed.action_items) parsed.action_items = [];
if (!parsed.deadline_reminders) parsed.deadline_reminders = [];
if (!parsed.calendar_availability) parsed.calendar_availability = null;
if (!parsed.escalation_required) parsed.escalation_required = false;
parsed.action_items = parsed.action_items.map(item => ({
  ...item,
  is_external: item.is_external || false,
  channel: item.channel || (item.is_external ? 'email' : 'teams_chat')
}));
return [{ json: parsed }];

const data = $('Parse Agent Output').item.json;
const followup = data.follow_up_meeting || {};
const date = followup.date || '2026-06-13';
return [{ json: {
  meeting_date: date,
  start_check: date + 'T08:00:00Z',
  end_check: date + 'T11:00:00Z',
  meeting_title: followup.title || 'Bosch Integration Review',
  meeting_time: followup.time || '09:00',
  meeting_duration: followup.duration_minutes || 60,
  meeting_agenda: followup.agenda || 'Review integration progress'
}}];

const calResponse = $input.first().json;
const calInput = $('Build Calendar Check URL').item.json;
const events = calResponse.value || [];
const conflicts = events.filter(e => e.subject && !e.subject.includes('NEURA AI'));
const hasConflict = conflicts.length > 0;
const availabilityNote = hasConflict
  ? '⚠ CONFLICT on ' + calInput.meeting_date + ' ' + calInput.meeting_time + ': ' + conflicts.map(e => '"' + e.subject + '"').join(', ')
  : '✅ Calendar confirmed available on ' + calInput.meeting_date + ' at ' + calInput.meeting_time;
// Calculate next days without Date() (not allowed in n8n)
function addDays(dateStr, n) {
  const p = dateStr.split('-').map(Number);
  let y = p[0], m = p[1], d = p[2] + n;
  const dim = [0,31,(y%4===0&&(y%100!==0||y%400===0))?29:28,31,30,31,30,31,31,30,31,30,31];
  while (d > dim[m]) { d -= dim[m]; m++; if (m > 12) { m = 1; y++; } }
  return y + '-' + String(m).padStart(2,'0') + '-' + String(d).padStart(2,'0');
}
const d = calInput.meeting_date;
const nd1 = addDays(d, 1);
const nd2 = addDays(d, 2);
const suggestedTimes = hasConflict ? [
  { label: 'Same day — afternoon', date: d,   time: '14:00', datetime: d   + 'T14:00:00', display: d   + ' at 14:00–15:00' },
  { label: 'Next day — morning',   date: nd1, time: '09:00', datetime: nd1 + 'T09:00:00', display: nd1 + ' at 09:00–10:00' },
  { label: 'Next day — afternoon', date: nd1, time: '14:00', datetime: nd1 + 'T14:00:00', display: nd1 + ' at 14:00–15:00' },
  { label: '+2 days — morning',    date: nd2, time: '09:00', datetime: nd2 + 'T09:00:00', display: nd2 + ' at 09:00–10:00' }
] : [];
return [{ json: {
  title: calInput.meeting_title, date: d, time: calInput.meeting_time,
  duration_minutes: calInput.meeting_duration, agenda: calInput.meeting_agenda,
  is_free: !hasConflict, availability_note: availabilityNote,
  conflict_count: conflicts.length, conflict_subjects: conflicts.map(e => e.subject),
  suggested_times: suggestedTimes
}}];

const calCheck = $input.first().json;
const data = $('Parse Agent Output').item.json;

const internalItems = (data.action_items || []).filter(i => !i.is_external);
const externalEmails = data.external_emails || [];
const reminders = data.deadline_reminders || [];
const followup = data.follow_up_meeting || null;
const externals = data.external_participants || [];
const hasExternal = data.external_participants_detected;
const recurringBlockers = (data.blockers || []).filter(b => b.is_recurring);
const risks = data.risk_flags || [];
const escalation = data.escalation_required;
const escalationReason = data.escalation_reason || '';

const rawApprove = $execution.resumeUrl + '&approved=true';
const rawReject = $execution.resumeUrl + '&approved=false';
const resumeUrl = 'http://localhost:8080?action=approve&n8n=' + encodeURIComponent(rawApprove);
const rejectUrl = 'http://localhost:8080?action=reject&n8n=' + encodeURIComponent(rawReject);
const n8nApproveUrl = rawApprove;
const n8nRejectUrl = rawReject;

const pc = { critical: '#dc3545', high: '#fd7e14', medium: '#ffc107', low: '#6c757d' };

// Escalation banner
let escalationHtml = escalation
  ? '<div style="background:#fff0f0;border:2px solid #dc3545;border-radius:6px;padding:12px;margin-bottom:14px"><b style="color:#dc3545">⚠ ESCALATION REQUIRED</b><br><span style="font-size:13px">' + escalationReason + '</span></div>'
  : '';

// External warning
let warningHtml = (hasExternal && externals.length)
  ? '<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:6px;padding:12px;margin-bottom:14px"><b>External participants:</b> ' + externals.join(', ') + '<br><span style="font-size:13px">Formal emails to external parties require your explicit approval.</span></div>'
  : '';

// Internal Teams Chat items
let teamsHtml = '';
internalItems.forEach(item => {
  const pColor = pc[item.priority] || '#6c757d';
  teamsHtml += '<div style="border:1px solid #5b5fc7;border-radius:6px;padding:12px;margin:6px 0;background:#f3f2fc">';
  teamsHtml += '<p style="margin:0 0 4px 0"><b>💬 Teams Chat → ' + item.owner_name + '</b> <span style="background:#5b5fc7;color:white;font-size:11px;padding:2px 6px;border-radius:3px">TEAMS CHAT</span></p>';
  teamsHtml += '<p style="margin:0 0 4px 0;color:#555;font-size:13px">' + item.owner_email + '</p>';
  teamsHtml += '<p style="margin:0 0 4px 0"><b>Task:</b> ' + item.task + '</p>';
  teamsHtml += '<p style="margin:0"><b>Deadline:</b> ' + item.deadline + ' &nbsp;<b style="color:' + pColor + '">' + (item.priority || 'medium').toUpperCase() + '</b>';
  if (item.depends_on) teamsHtml += ' &nbsp;<span style="color:#666;font-size:12px">Depends on: ' + item.depends_on + '</span>';
  teamsHtml += '</p></div>';
});

// External formal email drafts
let emailsHtml = '';
externalEmails.forEach(ext => {
  const uColor = pc[ext.urgency] || '#dc3545';
  emailsHtml += '<div style="border:1px solid #dc3545;border-radius:6px;padding:12px;margin:6px 0;background:#fff8f8">';
  emailsHtml += '<p style="margin:0 0 4px 0"><b>✉ Formal Email → ' + ext.recipient_name + '</b> <span style="background:#dc3545;color:white;font-size:11px;padding:2px 6px;border-radius:3px">EXTERNAL · ' + ext.company + '</span></p>';
  emailsHtml += '<p style="margin:0 0 4px 0;color:#555;font-size:13px">' + ext.recipient_email + '</p>';
  emailsHtml += '<p style="margin:0 0 4px 0"><b>Subject:</b> ' + ext.subject + '</p>';
  emailsHtml += '<p style="margin:0 0 6px 0"><b>Commitment:</b> ' + ext.commitment_date + ' &nbsp;<b style="color:' + uColor + '">' + (ext.urgency || 'high').toUpperCase() + '</b></p>';
  emailsHtml += '<details><summary style="cursor:pointer;font-size:12px;color:#0066cc">▶ Preview email body</summary>';
  emailsHtml += '<pre style="margin:8px 0 0;font-size:12px;color:#333;white-space:pre-wrap;font-family:Arial,sans-serif;background:#f9f9f9;padding:10px;border-radius:4px">' + ext.body + '</pre></details>';
  emailsHtml += '</div>';
});

// Calendar availability badge and conflict alternatives
const calBadge = calCheck.is_free
  ? '<span style="background:#28a745;color:white;font-size:11px;padding:2px 8px;border-radius:3px;margin-left:6px">✅ AVAILABLE</span>'
  : '<span style="background:#dc3545;color:white;font-size:11px;padding:2px 8px;border-radius:3px;margin-left:6px">⚠ CONFLICT</span>';

// Conflict alternatives section
let conflictHtml = '';
if (!calCheck.is_free && calCheck.suggested_times && calCheck.suggested_times.length > 0) {
  conflictHtml = '<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:6px;padding:12px;margin:6px 0">';
  conflictHtml += '<p style="margin:0 0 8px 0"><b>⚠ Calendar conflict detected — if there is a conflict, the human will be shown alternatives to pick from in the demo page</b></p>';
  conflictHtml += '<p style="margin:0 0 6px 0;font-size:13px">Suggested alternative times:</p>';
  calCheck.suggested_times.forEach(st => {
    conflictHtml += '<p style="margin:2px 0;font-size:13px">• ' + st.label + ': <b>' + st.display + '</b></p>';
  });
  conflictHtml += '</div>';
}

// Follow-up meeting
let meetingHtml = '';
if (followup) {
  meetingHtml = '<div style="border:1px solid #0d6efd;border-radius:6px;padding:12px;margin:6px 0;background:#f0f4ff">';
  meetingHtml += '<p style="margin:0 0 6px 0"><b>📅 Teams Meeting: ' + followup.title + '</b>' + calBadge + '</p>';
  meetingHtml += '<p style="margin:0 0 4px 0">Date: <b>' + followup.date + ' at ' + followup.time + '</b> (' + followup.duration_minutes + ' min)</p>';
  meetingHtml += '<p style="margin:0 0 4px 0">Agenda: ' + followup.agenda + '</p>';
  meetingHtml += '<p style="margin:4px 0 0;font-size:12px;color:' + (calCheck.is_free ? '#28a745' : '#dc3545') + '">';
  meetingHtml += 'Real calendar verified via Graph API · ' + calCheck.availability_note;
  meetingHtml += '</p>';
  meetingHtml += '</div>';
  if (conflictHtml) meetingHtml += conflictHtml;
}

// Deadline reminders
let remindersHtml = '';
if (reminders.length > 0) {
  remindersHtml = '<h4 style="border-bottom:1px solid #0d6efd;padding-bottom:6px;color:#0d6efd">⏰ Deadline Reminders — ' + reminders.length + ' calendar events to create</h4>';
  reminders.forEach(r => {
    const pColor = pc[r.priority] || '#ffc107';
    remindersHtml += '<div style="border:1px solid #dee2e6;border-radius:6px;padding:8px 12px;margin:4px 0;background:#f8f9fa">';
    remindersHtml += '<b style="color:' + pColor + '">⏰</b> ' + r.title + ' — deadline: <b>' + r.deadline + '</b>';
    remindersHtml += ' <span style="color:#555;font-size:12px">(' + r.owner_name + ')</span>';
    if (r.reminder_note) remindersHtml += '<br><span style="font-size:12px;color:#666">' + r.reminder_note + '</span>';
    remindersHtml += '</div>';
  });
}

// Recurring blockers
let blockersHtml = '';
if (recurringBlockers.length > 0) {
  blockersHtml = '<h4 style="color:#dc3545;border-bottom:1px solid #e0e0e0;padding-bottom:6px">Recurring Blockers Detected</h4>';
  recurringBlockers.forEach(b => {
    blockersHtml += '<p style="margin:4px 0">&#8226; <b>' + b.description + '</b> (seen ' + b.occurrences + '&times;) &mdash; ' + b.owner;
    if (b.escalation_needed) blockersHtml += ' <b style="color:#dc3545">&#8594; Escalation needed</b>';
    blockersHtml += '</p>';
  });
}

// Risk flags
let risksHtml = '';
if (risks.length > 0) {
  risksHtml = '<h4 style="color:#fd7e14">Risk Flags</h4>';
  risks.forEach(r => { risksHtml += '<p style="margin:4px 0">&#8226; ' + r + '</p>'; });
}

const totalActions = internalItems.length + externalEmails.length;
const subject = '[v4 Review Required] ' + internalItems.length + ' Teams chats + ' + externalEmails.length + ' external emails + ' + reminders.length + ' deadline reminders' + (escalation ? ' — ESCALATION REQUIRED' : '');

let html = '<div style="font-family:Arial,sans-serif;max-width:640px;color:#1a1a1a">';
html += '<h2 style="color:#1a1a2e;margin-bottom:4px">NEURA AI Meeting Agent v4</h2>';
html += '<h3 style="color:#e63946;margin-top:0">Review &amp; Approve Before Sending</h3>';
html += escalationHtml + warningHtml;
html += '<h4 style="border-bottom:1px solid #e0e0e0;padding-bottom:6px">Meeting Summary</h4>';
html += '<p>' + (data.meeting_summary || '') + '</p>';
if (internalItems.length > 0) {
  html += '<h4 style="border-bottom:1px solid #5b5fc7;padding-bottom:6px;color:#5b5fc7">💬 Teams Chat Notifications (' + internalItems.length + ')</h4>';
  html += teamsHtml;
}
if (externalEmails.length > 0) {
  html += '<h4 style="border-bottom:1px solid #dc3545;padding-bottom:6px;color:#dc3545">✉ Formal Emails — External Parties (' + externalEmails.length + ')</h4>';
  html += emailsHtml;
}
if (meetingHtml) {
  html += '<h4 style="border-bottom:1px solid #e0e0e0;padding-bottom:6px">Teams Meeting to Schedule</h4>';
  html += meetingHtml;
}
if (remindersHtml) html += remindersHtml;
if (blockersHtml) html += blockersHtml;
if (risksHtml) html += risksHtml;
html += '<br><hr style="border:none;border-top:1px solid #e0e0e0">';
html += '<p><b>If you approve:</b> ' + internalItems.length + ' Teams Chats + ' + externalEmails.length + ' external emails + ' + reminders.length + ' deadline calendar events + 1 Teams meeting = everything executes in the next 15 seconds.</p>';
html += '<table style="margin-top:12px"><tr>';
html += '<td><a href="http://localhost:8080/v3.html" style="background:#1f6feb;color:white;padding:14px 36px;text-decoration:none;border-radius:6px;font-size:16px;font-weight:bold;display:inline-block">✏ Review &amp; Edit in UI</a></td>';
html += '<td style="width:12px"></td>';
html += '<td><a href="' + resumeUrl + '" style="background:#28a745;color:white;padding:10px 20px;text-decoration:none;border-radius:6px;font-size:13px;font-weight:bold;display:inline-block">Quick Approve</a></td>';
html += '<td style="width:12px"></td>';
html += '<td><a href="' + rejectUrl + '" style="background:#dc3545;color:white;padding:10px 20px;text-decoration:none;border-radius:6px;font-size:13px;font-weight:bold;display:inline-block">Reject</a></td>';
html += '</tr></table>';
html += '<p style="font-size:12px;color:#666;margin-top:8px">"Review &amp; Edit in UI" opens the browser panel where you can edit any item before sending. "Quick Approve" sends everything as-is.</p>';
html += '<br><hr style="border:none;border-top:1px solid #e0e0e0"><p style="color:#999;font-size:12px"><i>NEURA AI Meeting Agent v4 | Teams + External Email + Calendar + Apply Edits | Powered by Futurice</i></p>';
html += '</div>';

return [{ json: {
  subject, html,
  resume_url: resumeUrl, reject_url: rejectUrl,
  n8n_approve_url: n8nApproveUrl, n8n_reject_url: n8nRejectUrl,
  item_count: totalActions,
  internal_items: internalItems,
  external_emails: externalEmails,
  deadline_reminders: reminders,
  calendar_check: calCheck,
  follow_up_meeting: followup,
  meeting_summary: data.meeting_summary,
  external_participants: externals,
  has_external: hasExternal,
  blockers: recurringBlockers,
  escalation_required: escalation,
  escalation_reason: escalationReason
}}];

const waitOutput = $input.first().json;
// Wait node captures POST body in $json.body, query in $json.query
const body = waitOutput.body || {};
const editedItems = body.edited_items || null;
const editedEmails = body.edited_emails || null;
const editedMeeting = body.edited_meeting || null;
const original = $('Parse Agent Output').item.json;
return [{ json: {
  final_internal_items: editedItems || (original.action_items || []).filter(i => !i.is_external),
  final_external_emails: editedEmails || (original.external_emails || []),
  final_meeting: editedMeeting || original.follow_up_meeting,
  deadline_reminders: original.deadline_reminders || [],
  has_edits: !!(editedItems || editedEmails || editedMeeting)
}}];

const edits = $('Apply Edits').item.json;
const items = edits.final_internal_items || [];
if (items.length === 0) return [{ json: { status: 'no_internal_items' } }];
const byOwner = {};
items.forEach(item => {
  const key = item.owner_email;
  if (!byOwner[key]) byOwner[key] = { owner_name: item.owner_name, owner_email: item.owner_email, tasks: [] };
  byOwner[key].tasks.push({ task: item.task, deadline: item.deadline, priority: item.priority, depends_on: item.depends_on || null });
});
return Object.values(byOwner).map(person => ({ json: person }));

const p = $input.first().json;
const tasks = p.tasks || [];
const pLabel = { critical: 'CRITICAL', high: 'HIGH', medium: 'MEDIUM', low: 'LOW' };
const lines = tasks.map((t, i) => {
  let s = (i + 1) + '. [' + (pLabel[t.priority] || 'MEDIUM') + '] ' + t.task + '\n   Due: ' + t.deadline;
  if (t.depends_on) s += '\n   Depends on: ' + t.depends_on;
  return s;
}).join('\n\n');
const count = tasks.length;
const reviewDate = ($('Apply Edits').item.json.final_meeting || {}).date || 'TBD';
return [{ json: {
  owner_name: p.owner_name,
  owner_email: p.owner_email,
  msg_subject: '[Teams Chat \u2192 ' + p.owner_name + '] ' + count + ' Action Item' + (count > 1 ? 's' : '') + ' \u2014 Sprint 7 Review',
  msg_body: 'Hi ' + p.owner_name + ',\n\n' + count + ' action item' + (count > 1 ? 's' : '') + ' from today\'s Sprint 7 review:\n\n' + lines + '\n\nFollow-up review: ' + reviewDate + '\n\n\u2014 NEURA AI Meeting Co-Pilot v4 | Futurice\n\n[DEMO] Intended for: ' + p.owner_email
}}];

const edits = $('Apply Edits').item.json;
const emails = edits.final_external_emails || [];
if (emails.length === 0) return [{ json: { status: 'no_external_emails' } }];
return emails.map(email => ({ json: email }));

const edits = $('Apply Edits').item.json;
const originalCal = $('Process Calendar Result').item.json;
const fm = edits.final_meeting || {};
const date = fm.date || originalCal.date || '2026-06-13';
const time = fm.time || originalCal.time || '09:00';
const isRescheduled = fm.date && fm.date !== originalCal.date;
return [{ json: {
  title: (fm.title || originalCal.title) + (isRescheduled ? ' [Rescheduled]' : ''),
  date, time,
  duration_minutes: fm.duration_minutes || originalCal.duration_minutes || 60,
  agenda: fm.agenda || originalCal.agenda || 'Review integration progress',
  is_rescheduled: isRescheduled,
  availability_note: originalCal.availability_note || '✅ Calendar confirmed available'
}}];

const edits = $('Apply Edits').item.json;
const reminders = edits.deadline_reminders || [];
if (reminders.length === 0) return [{ json: { status: 'no_reminders' } }];
return reminders.map(r => ({ json: r }));
